ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?university_name ?library_name WHERE {
  ?lb a :Libraries .
  ?lc a :Universities .
  ?lb p:hasUniversity ?lc .
  ?lc p:university_name ?university_name .
  ?lb p:library_name ?library_name .
} }
  full: { SELECT ?university_name ?name ?library_name WHERE {
  ?lb a :Libraries .
  ?lc a :Buildings .
  ?lb p:hasBuilding_Name ?lc .
  ?un a :Universities .
  ?lb p:hasUniversity ?un .
  ?un p:university_name ?university_name .
  ?lc p:name ?name .
  ?lb p:library_name ?library_name .
} }
  component_2: { SELECT ?name ?library_name WHERE {
  ?lb a :Libraries .
  ?lc a :Buildings .
  ?lb p:hasBuilding_Name ?lc .
  ?lc p:name ?name .
  ?lb p:library_name ?library_name .
} }
}

PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?university_name WHERE {
  ?lb a :Libraries .
  ?lc a :Universities .
  ?lb p:hasUniversity ?lc .
  ?lc p:university_name ?university_name .
  ?lb p:library_name ?library_name_f .
  FILTER(STR(?library_name_f) = STR("Library A"))
} }
  component_2: { SELECT ?name WHERE {
  ?lb a :Libraries .
  ?lc a :Buildings .
  ?lb p:hasBuilding_Name ?lc .
  ?lc p:name ?name .
  ?lb p:library_name ?library_name_f .
  FILTER(STR(?library_name_f) = STR("Library A"))
} }
  full: { SELECT ?university_name ?name WHERE {
  ?lb a :Libraries .
  ?lc a :Buildings .
  ?lb p:hasBuilding_Name ?lc .
  ?un a :Universities .
  ?lb p:hasUniversity ?un .
  ?un p:university_name ?university_name .
  ?lc p:name ?name .
  ?lb p:library_name ?library_name_f .
  FILTER(STR(?library_name_f) = STR("Library A"))
} }
}
